import { useEffect, useState, useCallback, useRef } from 'react';
import axios from 'axios';
import {
  LineChart, Line, ResponsiveContainer, Tooltip as ReTooltip, AreaChart, Area,
  XAxis, YAxis, CartesianGrid, Legend,
} from 'recharts';

const API = process.env.REACT_APP_API_URL || 'http://localhost:8000';

/* ─────────────────────── helpers ─────────────────────── */
const fmtTime = (iso) => {
  if (!iso) return '—';
  return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
};
const fmtDate = (iso) => {
  if (!iso) return '—';
  return new Date(iso).toLocaleString([], { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });
};
const timeAgo = (iso) => {
  if (!iso) return '—';
  const diff = (Date.now() - new Date(iso).getTime()) / 1000;
  if (diff < 60) return `${Math.round(diff)}s ago`;
  if (diff < 3600) return `${Math.round(diff / 60)}m ago`;
  return `${Math.round(diff / 3600)}h ago`;
};

const severityColor = (s) => {
  if (!s) return '#4ade80';
  const m = { Critical: '#ff4757', High: '#ff6b35', Medium: '#ffb347', Low: '#f7e25a', Normal: '#4ade80' };
  return m[s] || '#4ade80';
};
const nodeStatusColor = (node) => {
  if (node.active_anomalies > 0) {
    const sev = node.latest_anomaly?.severity;
    return severityColor(sev);
  }
  if (node.status === 'critical') return '#ff4757';
  if (node.status === 'warning') return '#ffb347';
  if (node.status === 'online') return '#4ade80';
  return '#6c757d';
};

const cpuValue = (node) => {
  const m = node.latest_metrics?.find(x => x.metric_name === 'cpu_usage_percent');
  return m ? m.value : null;
};
const memValue = (node) => {
  const m = node.latest_metrics?.find(x => x.metric_name === 'memory_usage_percent');
  return m ? m.value : null;
};
const netValue = (node) => {
  const m = node.latest_metrics?.find(x => x.metric_name === 'network_rx_mbps');
  return m ? m.value : null;
};

/* ─────────────────────── Sparkline ─────────────────────── */
function Sparkline({ data = [], color = '#00d4ff', label }) {
  if (!data.length) return <div style={{ height: 38, display: 'flex', alignItems: 'center', color: '#444', fontSize: 11 }}>No data</div>;
  const pts = data.slice(-20).map((d, i) => ({ i, v: d.value }));
  return (
    <div>
      <div style={{ fontSize: 10, color: '#aaa', marginBottom: 2 }}>{label}</div>
      <ResponsiveContainer width="100%" height={38}>
        <AreaChart data={pts} margin={{ top: 2, right: 0, left: 0, bottom: 2 }}>
          <defs>
            <linearGradient id={`sg-${color.replace('#', '')}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor={color} stopOpacity={0.3} />
              <stop offset="95%" stopColor={color} stopOpacity={0} />
            </linearGradient>
          </defs>
          <Area type="monotone" dataKey="v" stroke={color} strokeWidth={1.5}
            fill={`url(#sg-${color.replace('#', '')})`} dot={false} isAnimationActive={false} />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}

/* ─────────────────────── Stat Pill ─────────────────────── */
function StatPill({ label, value, color = '#00d4ff', icon }) {
  return (
    <div style={{
      background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)',
      borderRadius: 12, padding: '10px 18px', minWidth: 110, flex: '1 1 110px',
      display: 'flex', flexDirection: 'column', gap: 4,
      backdropFilter: 'blur(8px)',
    }}>
      <div style={{ fontSize: 11, color: '#888', letterSpacing: 1, textTransform: 'uppercase' }}>
        {icon} {label}
      </div>
      <div style={{ fontSize: 24, fontWeight: 700, color, lineHeight: 1 }}>{value ?? '—'}</div>
    </div>
  );
}

/* ─────────────────────── Node Card ─────────────────────── */
function NodeCard({ node, onClick }) {
  const border = nodeStatusColor(node);
  const hasAnomaly = node.active_anomalies > 0;
  const cpu = cpuValue(node);
  const mem = memValue(node);
  const net = netValue(node);

  return (
    <div
      onClick={() => onClick(node)}
      style={{
        position: 'relative', cursor: 'pointer',
        background: 'rgba(255,255,255,0.04)',
        border: `1.5px solid ${border}40`,
        borderLeft: `3px solid ${border}`,
        borderRadius: 14,
        padding: '14px 16px',
        backdropFilter: 'blur(12px)',
        transition: 'transform 0.18s ease, box-shadow 0.18s ease',
        boxShadow: hasAnomaly ? `0 0 18px ${border}30, 0 2px 12px rgba(0,0,0,0.4)` : '0 2px 12px rgba(0,0,0,0.35)',
        overflow: 'hidden',
      }}
      onMouseEnter={e => {
        e.currentTarget.style.transform = 'translateY(-3px)';
        e.currentTarget.style.boxShadow = `0 8px 28px ${border}40, 0 4px 16px rgba(0,0,0,0.5)`;
      }}
      onMouseLeave={e => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = hasAnomaly ? `0 0 18px ${border}30, 0 2px 12px rgba(0,0,0,0.4)` : '0 2px 12px rgba(0,0,0,0.35)';
      }}
    >
      {/* Anomaly pulse ring */}
      {hasAnomaly && (
        <span style={{
          position: 'absolute', top: 10, right: 10,
          width: 10, height: 10, borderRadius: '50%',
          background: border, boxShadow: `0 0 0 0 ${border}`,
          animation: 'pulse 1.6s ease-out infinite',
        }} />
      )}

      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}>
        <div>
          <div style={{ fontWeight: 700, fontSize: 13, color: '#e8eaf0', letterSpacing: 0.3 }}>
            {node.hostname}
          </div>
          <div style={{ fontSize: 11, color: '#666', marginTop: 1 }}>{node.ip_address || '—'}</div>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 4 }}>
          <div style={{
            fontSize: 10, fontWeight: 600, padding: '2px 8px', borderRadius: 99,
            background: `${border}22`, color: border, letterSpacing: 0.5,
            textTransform: 'uppercase',
          }}>
            {node.status || 'unknown'}
          </div>
          {node.active_users > 0 && (
            <div style={{ fontSize: 10, color: '#9b8fff', display: 'flex', alignItems: 'center', gap: 4 }}>
              👤 {node.active_users} user{node.active_users > 1 ? 's' : ''}
            </div>
          )}
        </div>
      </div>

      {/* Metric values row */}
      <div style={{ display: 'flex', gap: 12, marginBottom: 10 }}>
        {cpu !== null && (
          <div style={{ fontSize: 11 }}>
            <span style={{ color: '#888' }}>CPU </span>
            <span style={{ color: cpu > 80 ? '#ff4757' : cpu > 60 ? '#ffb347' : '#4ade80', fontWeight: 700 }}>
              {cpu.toFixed(1)}%
            </span>
          </div>
        )}
        {mem !== null && (
          <div style={{ fontSize: 11 }}>
            <span style={{ color: '#888' }}>MEM </span>
            <span style={{ color: mem > 85 ? '#ff4757' : mem > 70 ? '#ffb347' : '#4ade80', fontWeight: 700 }}>
              {mem.toFixed(1)}%
            </span>
          </div>
        )}
        {net !== null && (
          <div style={{ fontSize: 11 }}>
            <span style={{ color: '#888' }}>NET </span>
            <span style={{ color: '#00d4ff', fontWeight: 700 }}>{net.toFixed(1)} MB/s</span>
          </div>
        )}
      </div>

      {/* Sparklines */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        <Sparkline data={node.sparklines?.cpu_usage_percent} color="#00d4ff" label="CPU %" />
        <Sparkline data={node.sparklines?.memory_usage_percent} color="#9b8fff" label="MEM %" />
      </div>

      {/* Anomaly badge */}
      {hasAnomaly && (
        <div style={{
          marginTop: 10, padding: '5px 10px', borderRadius: 8,
          background: `${border}15`, border: `1px solid ${border}40`,
          fontSize: 10, color: border, lineHeight: 1.4,
        }}>
          🚨 <strong>{node.active_anomalies} anomal{node.active_anomalies > 1 ? 'ies' : 'y'}</strong>
          {node.latest_anomaly?.severity && ` — ${node.latest_anomaly.severity}`}
          {node.latest_anomaly?.description && (
            <div style={{ marginTop: 2, color: '#bbb', fontSize: 9 }} title={node.latest_anomaly.description}>
              {node.latest_anomaly.description.slice(0, 60)}…
            </div>
          )}
        </div>
      )}
    </div>
  );
}

/* ─────────────────────── Anomaly Feed ─────────────────────── */
function AnomalyFeed({ feed }) {
  return (
    <div style={{
      background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)',
      borderRadius: 16, padding: '16px', backdropFilter: 'blur(10px)',
      display: 'flex', flexDirection: 'column', gap: 0, maxHeight: '100%', overflow: 'hidden',
    }}>
      <div style={{ fontWeight: 700, fontSize: 13, color: '#e8eaf0', marginBottom: 12, letterSpacing: 0.5 }}>
        🔔 Live Anomaly Feed
      </div>
      <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 8 }}>
        {feed.length === 0 && (
          <div style={{ color: '#4ade80', fontSize: 12, padding: 8 }}>✅ No active anomalies</div>
        )}
        {feed.map((ev) => {
          const sc = severityColor(ev.severity);
          return (
            <div key={ev.id} style={{
              padding: '8px 10px', borderRadius: 10,
              background: `${sc}08`, borderLeft: `2px solid ${sc}`,
              fontSize: 11, lineHeight: 1.5,
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 2 }}>
                <span style={{ fontWeight: 700, color: sc }}>{ev.severity}</span>
                <span style={{ color: '#555', fontSize: 10 }}>{timeAgo(ev.detected_at)}</span>
              </div>
              <div style={{ color: '#bbb', fontWeight: 600 }}>{ev.hostname}</div>
              <div style={{ color: '#888' }}>{ev.metric_name?.replace(/_/g, ' ')}</div>
              <div style={{ color: '#666', fontSize: 10 }}>{ev.description?.slice(0, 70)}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ─────────────────────── Node Drilldown Modal ─────────────────────── */
function DrilldownModal({ node, onClose }) {
  const [anomalies, setAnomalies] = useState([]);
  const [users, setUsers] = useState([]);
  const [processes, setProcesses] = useState([]);
  const [metrics, setMetrics] = useState([]);
  const [tab, setTab] = useState('overview');

  useEffect(() => {
    if (!node) return;
    const id = node.id;
    axios.get(`${API}/api/cluster/node/${id}/anomalies?limit=30`).then(r => setAnomalies(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/node/${id}/users`).then(r => setUsers(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/node/${id}/processes`).then(r => setProcesses(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/node/${id}/metrics?limit=120`).then(r => setMetrics(r.data)).catch(() => {});
  }, [node]);

  if (!node) return null;

  // Build chart data by metric name
  const buildChart = (metricName) => {
    return metrics
      .filter(m => m.metric_name === metricName)
      .slice(0, 60)
      .reverse()
      .map((m, i) => ({ i, value: parseFloat(m.value.toFixed(2)), time: fmtTime(m.timestamp) }));
  };

  const chartMetrics = [...new Set(metrics.map(m => m.metric_name))];
  const metricColors = ['#00d4ff', '#9b8fff', '#4ade80', '#ffb347', '#ff6b35'];

  const tabs = ['overview', 'metrics', 'anomalies', 'users', 'processes'];

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 1000,
      background: 'rgba(0,0,0,0.75)', backdropFilter: 'blur(6px)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      padding: 24,
    }} onClick={onClose}>
      <div style={{
        background: '#0d1117', border: '1px solid rgba(255,255,255,0.1)',
        borderRadius: 20, width: '100%', maxWidth: 860,
        maxHeight: '90vh', overflow: 'hidden',
        display: 'flex', flexDirection: 'column',
        boxShadow: '0 24px 80px rgba(0,0,0,0.8)',
      }} onClick={e => e.stopPropagation()}>

        {/* Modal Header */}
        <div style={{
          padding: '20px 24px', borderBottom: '1px solid rgba(255,255,255,0.06)',
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          background: 'rgba(0,212,255,0.04)',
        }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 800, color: '#e8eaf0', letterSpacing: 0.5 }}>
              🖥️ {node.hostname}
            </div>
            <div style={{ fontSize: 12, color: '#888', marginTop: 2 }}>
              {node.ip_address} · {node.os_version || 'Linux'} · {node.architecture || 'x86_64'}
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <div style={{
              padding: '4px 12px', borderRadius: 99, fontSize: 11, fontWeight: 700,
              background: `${nodeStatusColor(node)}22`, color: nodeStatusColor(node),
              textTransform: 'uppercase', letterSpacing: 0.5,
            }}>
              {node.status || 'unknown'}
            </div>
            <button onClick={onClose} style={{
              background: 'rgba(255,255,255,0.07)', border: '1px solid rgba(255,255,255,0.1)',
              color: '#aaa', borderRadius: 8, padding: '6px 14px', cursor: 'pointer', fontSize: 13,
            }}>✕ Close</button>
          </div>
        </div>

        {/* Tab bar */}
        <div style={{
          display: 'flex', borderBottom: '1px solid rgba(255,255,255,0.06)',
          padding: '0 24px',
        }}>
          {tabs.map(t => (
            <button key={t} onClick={() => setTab(t)} style={{
              background: 'none', border: 'none', cursor: 'pointer',
              padding: '12px 16px', fontSize: 12, fontWeight: 600,
              color: tab === t ? '#00d4ff' : '#666',
              borderBottom: tab === t ? '2px solid #00d4ff' : '2px solid transparent',
              textTransform: 'capitalize', letterSpacing: 0.5, transition: 'color 0.15s',
            }}>{t}</button>
          ))}
        </div>

        {/* Modal Body */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '20px 24px' }}>

          {/* ── Overview Tab ── */}
          {tab === 'overview' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
                {[
                  { label: 'Active Users', value: users.length, color: '#9b8fff', icon: '👤' },
                  { label: 'Processes', value: processes.length, color: '#00d4ff', icon: '⚙️' },
                  { label: 'Active Anomalies', value: node.active_anomalies, color: node.active_anomalies > 0 ? '#ff4757' : '#4ade80', icon: '🚨' },
                  { label: 'Open Incidents', value: node.open_incidents ?? 0, color: '#ffb347', icon: '📋' },
                ].map(p => <StatPill key={p.label} {...p} />)}
              </div>

              {/* Quick process table */}
              <div style={{ background: 'rgba(255,255,255,0.03)', borderRadius: 12, padding: 14 }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: '#aaa', marginBottom: 10, letterSpacing: 0.5 }}>
                  ⚙️ TOP PROCESSES
                </div>
                {processes.length === 0
                  ? <div style={{ color: '#555', fontSize: 12 }}>No process data</div>
                  : (
                    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 11 }}>
                      <thead>
                        <tr style={{ color: '#666' }}>
                          {['PID', 'USER', 'CPU%', 'MEM%', 'STATUS', 'COMMAND'].map(h => (
                            <th key={h} style={{ textAlign: 'left', padding: '4px 8px', fontWeight: 600, letterSpacing: 0.5 }}>{h}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {processes.slice(0, 8).map(p => (
                          <tr key={p.id} style={{ borderTop: '1px solid rgba(255,255,255,0.04)' }}>
                            <td style={{ padding: '5px 8px', color: '#888' }}>{p.pid}</td>
                            <td style={{ padding: '5px 8px', color: '#9b8fff' }}>{p.username}</td>
                            <td style={{ padding: '5px 8px', color: p.cpu_pct > 70 ? '#ff4757' : p.cpu_pct > 40 ? '#ffb347' : '#4ade80', fontWeight: 700 }}>
                              {p.cpu_pct?.toFixed(1)}
                            </td>
                            <td style={{ padding: '5px 8px', color: '#aaa' }}>{p.mem_pct?.toFixed(1)}</td>
                            <td style={{ padding: '5px 8px' }}>
                              <span style={{
                                padding: '1px 6px', borderRadius: 4, fontSize: 9, fontWeight: 700,
                                background: p.status === 'running' ? '#4ade8022' : '#66666622',
                                color: p.status === 'running' ? '#4ade80' : '#888',
                              }}>{p.status}</span>
                            </td>
                            <td style={{ padding: '5px 8px', color: '#ccc', maxWidth: 280, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
                              title={p.command}>{p.command}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  )}
              </div>

              {/* Quick user table */}
              <div style={{ background: 'rgba(255,255,255,0.03)', borderRadius: 12, padding: 14 }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: '#aaa', marginBottom: 10, letterSpacing: 0.5 }}>
                  👤 ACTIVE SESSIONS
                </div>
                {users.length === 0
                  ? <div style={{ color: '#555', fontSize: 12 }}>No active sessions</div>
                  : (
                    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 11 }}>
                      <thead>
                        <tr style={{ color: '#666' }}>
                          {['USERNAME', 'TERMINAL', 'FROM', 'LOGIN TIME'].map(h => (
                            <th key={h} style={{ textAlign: 'left', padding: '4px 8px', fontWeight: 600, letterSpacing: 0.5 }}>{h}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {users.map(u => (
                          <tr key={u.id} style={{ borderTop: '1px solid rgba(255,255,255,0.04)' }}>
                            <td style={{ padding: '5px 8px', color: '#9b8fff', fontWeight: 600 }}>{u.username}</td>
                            <td style={{ padding: '5px 8px', color: '#888' }}>{u.terminal}</td>
                            <td style={{ padding: '5px 8px', color: '#aaa' }}>{u.remote_host}</td>
                            <td style={{ padding: '5px 8px', color: '#666' }}>{fmtDate(u.login_time)}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  )}
              </div>
            </div>
          )}

          {/* ── Metrics Tab ── */}
          {tab === 'metrics' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
              {chartMetrics.map((name, idx) => {
                const data = buildChart(name);
                const color = metricColors[idx % metricColors.length];
                return (
                  <div key={name} style={{ background: 'rgba(255,255,255,0.03)', borderRadius: 12, padding: 14 }}>
                    <div style={{ fontSize: 11, fontWeight: 700, color, marginBottom: 10, textTransform: 'uppercase', letterSpacing: 0.7 }}>
                      {name.replace(/_/g, ' ')}
                    </div>
                    <ResponsiveContainer width="100%" height={120}>
                      <AreaChart data={data}>
                        <defs>
                          <linearGradient id={`cg-${idx}`} x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor={color} stopOpacity={0.25} />
                            <stop offset="95%" stopColor={color} stopOpacity={0} />
                          </linearGradient>
                        </defs>
                        <CartesianGrid stroke="rgba(255,255,255,0.04)" strokeDasharray="3 3" />
                        <XAxis dataKey="time" tick={{ fill: '#555', fontSize: 10 }} interval="preserveStartEnd" />
                        <YAxis tick={{ fill: '#555', fontSize: 10 }} width={40} />
                        <ReTooltip contentStyle={{ background: '#111', border: `1px solid ${color}40`, borderRadius: 8, fontSize: 11 }} />
                        <Area type="monotone" dataKey="value" stroke={color} strokeWidth={2}
                          fill={`url(#cg-${idx})`} dot={false} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                );
              })}
              {chartMetrics.length === 0 && <div style={{ color: '#555', fontSize: 13 }}>No metric history available.</div>}
            </div>
          )}

          {/* ── Anomalies Tab ── */}
          {tab === 'anomalies' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {anomalies.length === 0 && <div style={{ color: '#4ade80', fontSize: 13 }}>✅ No anomalies detected for this node.</div>}
              {anomalies.map(ev => {
                const sc = severityColor(ev.severity);
                return (
                  <div key={ev.id} style={{
                    padding: '12px 14px', borderRadius: 10,
                    background: `${sc}08`, border: `1px solid ${sc}25`,
                    borderLeft: `3px solid ${sc}`,
                  }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
                      <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                        <span style={{ fontWeight: 700, fontSize: 12, color: sc }}>{ev.severity}</span>
                        <span style={{ fontSize: 11, color: '#888', background: 'rgba(255,255,255,0.06)', padding: '1px 7px', borderRadius: 5 }}>
                          {ev.detector}
                        </span>
                        <span style={{ fontSize: 11, color: '#666' }}>score: {ev.anomaly_score?.toFixed(3)}</span>
                      </div>
                      <span style={{ fontSize: 11, color: '#555' }}>{fmtDate(ev.detected_at)}</span>
                    </div>
                    <div style={{ fontSize: 11, color: '#aaa', marginBottom: 4 }}>
                      <strong style={{ color: '#ccc' }}>{ev.metric_name?.replace(/_/g, ' ')}</strong>
                      {ev.metric_value !== null && ` — value: ${ev.metric_value?.toFixed(2)}`}
                    </div>
                    <div style={{ fontSize: 11, color: '#888' }}>{ev.description}</div>
                    {ev.resolved && <div style={{ fontSize: 10, color: '#4ade80', marginTop: 4 }}>✓ Resolved</div>}
                  </div>
                );
              })}
            </div>
          )}

          {/* ── Users Tab ── */}
          {tab === 'users' && (
            <div>
              {users.length === 0
                ? <div style={{ color: '#555', fontSize: 13 }}>No active user sessions found on this node.</div>
                : (
                  <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
                    <thead>
                      <tr style={{ background: 'rgba(255,255,255,0.04)' }}>
                        {['USERNAME', 'TERMINAL', 'SOURCE IP / HOST', 'LOGGED IN AT', 'COLLECTED'].map(h => (
                          <th key={h} style={{ textAlign: 'left', padding: '10px 12px', color: '#666', fontWeight: 600, letterSpacing: 0.5, fontSize: 11 }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {users.map(u => (
                        <tr key={u.id} style={{ borderTop: '1px solid rgba(255,255,255,0.04)' }}>
                          <td style={{ padding: '9px 12px', color: '#9b8fff', fontWeight: 700 }}>{u.username}</td>
                          <td style={{ padding: '9px 12px', color: '#aaa' }}>{u.terminal}</td>
                          <td style={{ padding: '9px 12px', color: '#ccc' }}>{u.remote_host}</td>
                          <td style={{ padding: '9px 12px', color: '#888' }}>{fmtDate(u.login_time)}</td>
                          <td style={{ padding: '9px 12px', color: '#555', fontSize: 10 }}>{timeAgo(u.collected_at)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
            </div>
          )}

          {/* ── Processes Tab ── */}
          {tab === 'processes' && (
            <div>
              {processes.length === 0
                ? <div style={{ color: '#555', fontSize: 13 }}>No process data available.</div>
                : (
                  <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
                    <thead>
                      <tr style={{ background: 'rgba(255,255,255,0.04)' }}>
                        {['PID', 'USER', 'CPU%', 'MEM%', 'STATUS', 'COMMAND'].map(h => (
                          <th key={h} style={{ textAlign: 'left', padding: '10px 12px', color: '#666', fontWeight: 600, letterSpacing: 0.5, fontSize: 11 }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {processes.map(p => (
                        <tr key={p.id} style={{ borderTop: '1px solid rgba(255,255,255,0.04)' }}>
                          <td style={{ padding: '8px 12px', color: '#666' }}>{p.pid}</td>
                          <td style={{ padding: '8px 12px', color: '#9b8fff', fontWeight: 600 }}>{p.username}</td>
                          <td style={{ padding: '8px 12px', fontWeight: 700, color: p.cpu_pct > 70 ? '#ff4757' : p.cpu_pct > 40 ? '#ffb347' : '#4ade80' }}>
                            {p.cpu_pct?.toFixed(1)}
                          </td>
                          <td style={{ padding: '8px 12px', color: '#aaa' }}>{p.mem_pct?.toFixed(1)}</td>
                          <td style={{ padding: '8px 12px' }}>
                            <span style={{
                              padding: '2px 8px', borderRadius: 4, fontSize: 10, fontWeight: 700,
                              background: p.status === 'running' ? '#4ade8022' : '#66666622',
                              color: p.status === 'running' ? '#4ade80' : '#888',
                            }}>{p.status}</span>
                          </td>
                          <td style={{ padding: '8px 12px', color: '#ddd', fontFamily: 'monospace', fontSize: 11, maxWidth: 340, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
                            title={p.command}>{p.command}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
            </div>
          )}

        </div>
      </div>
    </div>
  );
}

/* ─────────────────────── Main App ─────────────────────── */
export default function App() {
  const [overview, setOverview] = useState(null);
  const [nodes, setNodes] = useState([]);
  const [feed, setFeed] = useState([]);
  const [selectedNode, setSelectedNode] = useState(null);
  const [now, setNow] = useState(new Date());
  const [lastRefresh, setLastRefresh] = useState(null);
  const [filterStatus, setFilterStatus] = useState('all');

  const fetchAll = useCallback(() => {
    axios.get(`${API}/api/cluster/overview`).then(r => setOverview(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/nodes`).then(r => setNodes(r.data)).catch(() => {});
    axios.get(`${API}/api/cluster/anomaly-feed?limit=60`).then(r => setFeed(r.data)).catch(() => {});
    setLastRefresh(new Date());
  }, []);

  useEffect(() => {
    fetchAll();
    const iv1 = setInterval(fetchAll, 30000);
    const iv2 = setInterval(() => setNow(new Date()), 1000);
    return () => { clearInterval(iv1); clearInterval(iv2); };
  }, [fetchAll]);

  const filtered = nodes.filter(n => {
    if (filterStatus === 'all') return true;
    if (filterStatus === 'anomaly') return n.active_anomalies > 0;
    return n.status === filterStatus;
  });

  const statusFilters = [
    { key: 'all', label: 'All Nodes' },
    { key: 'online', label: '🟢 Online' },
    { key: 'anomaly', label: '🔴 Anomaly' },
    { key: 'warning', label: '🟡 Warning' },
    { key: 'critical', label: '🔴 Critical' },
    { key: 'offline', label: '⚫ Offline' },
  ];

  return (
    <div style={{
      minHeight: '100vh', background: '#080c14',
      fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, sans-serif",
      color: '#e8eaf0',
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 6px; height: 6px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.12); border-radius: 3px; }
        @keyframes pulse {
          0% { box-shadow: 0 0 0 0 currentColor; opacity: 1; }
          70% { box-shadow: 0 0 0 8px transparent; opacity: 0.4; }
          100% { box-shadow: 0 0 0 0 transparent; opacity: 1; }
        }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: none; } }
        .node-card { animation: fadeIn 0.3s ease both; }
      `}</style>

      {/* ── Top Bar ── */}
      <div style={{
        position: 'sticky', top: 0, zIndex: 100,
        background: 'rgba(8,12,20,0.92)', backdropFilter: 'blur(16px)',
        borderBottom: '1px solid rgba(255,255,255,0.06)',
        padding: '0 28px', display: 'flex', alignItems: 'center',
        justifyContent: 'space-between', height: 56,
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
          <div style={{
            width: 32, height: 32, borderRadius: 8,
            background: 'linear-gradient(135deg, #00d4ff, #0066ff)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 16, fontWeight: 900,
          }}>⛽</div>
          <div>
            <div style={{ fontWeight: 800, fontSize: 15, letterSpacing: 0.5 }}>ONGC AI Cluster Monitor</div>
            <div style={{ fontSize: 10, color: '#555', letterSpacing: 0.5 }}>GANGLIA-STYLE HPC DASHBOARD</div>
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          {overview?.active_anomalies > 0 && (
            <div style={{
              display: 'flex', alignItems: 'center', gap: 6,
              background: 'rgba(255,71,87,0.15)', border: '1px solid rgba(255,71,87,0.3)',
              borderRadius: 8, padding: '4px 12px', fontSize: 11, color: '#ff4757', fontWeight: 700,
              animation: 'pulse 2s infinite',
            }}>
              🚨 {overview.active_anomalies} ANOMAL{overview.active_anomalies > 1 ? 'IES' : 'Y'} ACTIVE
            </div>
          )}
          <div style={{ fontSize: 12, color: '#555', fontFamily: 'monospace' }}>
            {now.toLocaleTimeString()}
          </div>
          <button onClick={fetchAll} style={{
            background: 'rgba(0,212,255,0.1)', border: '1px solid rgba(0,212,255,0.3)',
            color: '#00d4ff', borderRadius: 8, padding: '6px 14px', cursor: 'pointer',
            fontSize: 12, fontWeight: 600, transition: 'background 0.15s',
          }}>↺ Refresh</button>
        </div>
      </div>

      <div style={{ padding: '24px 28px', display: 'flex', flexDirection: 'column', gap: 20 }}>

        {/* ── Summary Strip ── */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
          <StatPill label="Total Nodes" value={overview?.total_nodes} color="#00d4ff" icon="🖥️" />
          <StatPill label="Online" value={overview?.healthy_nodes} color="#4ade80" icon="✅" />
          <StatPill label="Warnings" value={overview?.warnings} color="#ffb347" icon="⚠️" />
          <StatPill label="Critical" value={overview?.critical} color="#ff4757" icon="🔴" />
          <StatPill label="Offline" value={overview?.offline} color="#6c757d" icon="⚫" />
          <StatPill label="Active Alerts" value={overview?.active_alerts} color="#9b8fff" icon="🔔" />
          <StatPill label="Anomalies" value={overview?.active_anomalies} color={overview?.active_anomalies > 0 ? '#ff4757' : '#4ade80'} icon="🚨" />
          <StatPill label="Incidents" value={overview?.active_incidents} color="#ff6b35" icon="📋" />
        </div>

        {/* ── Filter bar ── */}
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
          {statusFilters.map(f => (
            <button key={f.key} onClick={() => setFilterStatus(f.key)} style={{
              background: filterStatus === f.key ? 'rgba(0,212,255,0.15)' : 'rgba(255,255,255,0.04)',
              border: filterStatus === f.key ? '1px solid rgba(0,212,255,0.5)' : '1px solid rgba(255,255,255,0.07)',
              color: filterStatus === f.key ? '#00d4ff' : '#888',
              borderRadius: 8, padding: '5px 14px', cursor: 'pointer', fontSize: 12, fontWeight: 600,
              transition: 'all 0.15s',
            }}>{f.label}</button>
          ))}
          <div style={{ marginLeft: 'auto', fontSize: 11, color: '#555' }}>
            {filtered.length} node{filtered.length !== 1 ? 's' : ''}
            {lastRefresh && ` · Updated ${timeAgo(lastRefresh.toISOString())}`}
          </div>
        </div>

        {/* ── Main layout: Node Grid + Anomaly Feed ── */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 280px', gap: 20, alignItems: 'start' }}>

          {/* Node Grid */}
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))',
            gap: 14,
          }}>
            {filtered.length === 0 && (
              <div style={{ color: '#555', fontSize: 13, gridColumn: '1/-1', padding: 20, textAlign: 'center' }}>
                {nodes.length === 0 ? '⏳ Connecting to backend…' : 'No nodes match this filter.'}
              </div>
            )}
            {filtered.map(node => (
              <div key={node.id} className="node-card">
                <NodeCard node={node} onClick={setSelectedNode} />
              </div>
            ))}
          </div>

          {/* Anomaly Feed */}
          <div style={{ position: 'sticky', top: 76, maxHeight: 'calc(100vh - 100px)' }}>
            <AnomalyFeed feed={feed} />
          </div>
        </div>

      </div>

      {/* ── Node Drilldown Modal ── */}
      {selectedNode && (
        <DrilldownModal
          node={selectedNode}
          onClose={() => setSelectedNode(null)}
        />
      )}
    </div>
  );
}
